SELECT a.id as id, a.user_id as user_id, u.user_name as userName, u.phonenumber as userPhone, a.vaccine_id as vaccine_id, v.name as vaccineName, v.manufacturer as manufacturer, v.suitable_age as suitableAge, a.appointment_date as appointment_date, a.time_slot as time_slot, a.status as status, a.phone as phone, a.remark as remark, a.create_time as create_time, a.update_time as update_time FROM vaccine_appointment a LEFT JOIN sys_user u ON a.user_id = u.user_id LEFT JOIN vaccine_information v ON a.vaccine_id = v.id
AND a.appointment_date = #{appointmentDate}
AND a.status = #{status}
AND a.vaccine_id = #{vaccineId}
AND a.user_id = #{userId}
AND v.name like concat('%', #{vaccineName}, '%')
AND ( u.user_name like concat('%', #{userName}, '%') OR u.nick_name like concat('%', #{userName}, '%') OR u.phonenumber like concat('%', #{userName}, '%') )
AND v.manufacturer like concat('%', #{manufacturer}, '%')
AND (a.phone like concat('%', #{phone}, '%') OR u.phonenumber like concat('%', #{phone}, '%'))
ORDER BY a.create_time DESC

SELECT a.id as id, a.vaccine_id as vaccine_id, v.name as vaccineName, a.appointment_date as appointment_date, v.manufacturer as manufacturer, a.time_slot as time_slot, a.status as status, a.phone as phone, a.remark as remark, a.create_time as create_time FROM vaccine_appointment a LEFT JOIN vaccine_information v ON a.vaccine_id = v.id WHERE a.user_id = #{userId}
AND a.status = #{status}
AND a.appointment_date = #{appointmentDate}
ORDER BY a.create_time DESC

